	private static final int DEFAULT_TRACE_LIMIT = 24_000;
	private static final int MAX_DISCONNECTED_FINITE_ANCHOR_ROWS = 64;
	private static final int MAX_CONNECTED_DP_STATES_PER_MASK = 4;

